/* ═══════════════════════════════════════════════════
   script.js  –  Top Resume Making Template
   Backend  : localStorage (simulated)
   Features : Auth, Resume Builder, Live Preview, Page Routing
═══════════════════════════════════════════════════ */

/* ── Owner / Default Photo ─────────────────────── */
const OWNER_PHOTO =
  "data:image/jpeg;base64,";

/* ════════════════════════════════════════════════
   SAFE STORAGE  (falls back to in-memory if localStorage unavailable)
════════════════════════════════════════════════ */
const _memStore = {};
const SafeStorage = {
  getItem(k) {
    try {
      return SafeStorage.getItem(k);
    } catch {
      return _memStore[k] ?? null;
    }
  },
  setItem(k, v) {
    try {
      SafeStorage.setItem(k, v);
    } catch {
      _memStore[k] = v;
    }
  },
  removeItem(k) {
    try {
      SafeStorage.removeItem(k);
    } catch {
      delete _memStore[k];
    }
  },
};
const DB = {
  users() {
    try {
      return JSON.parse(SafeStorage.getItem("trmt_users") || "[]");
    } catch {
      return [];
    }
  },
  session() {
    try {
      return JSON.parse(SafeStorage.getItem("trmt_session"));
    } catch {
      return null;
    }
  },
  register(name, email, phone, pass) {
    const u = this.users();
    if (u.find((x) => x.email === email))
      return { ok: false, msg: "Email already registered." };
    u.push({ name, email, phone, pass });
    SafeStorage.setItem("trmt_users", JSON.stringify(u));
    return { ok: true };
  },
  login(email, pass) {
    const u = this.users().find((x) => x.email === email && x.pass === pass);
    if (!u) return { ok: false, msg: "Invalid email or password." };
    SafeStorage.setItem("trmt_session", JSON.stringify(u));
    return { ok: true, user: u };
  },
  logout() {
    SafeStorage.removeItem("trmt_session");
  },
  saveResume(email, data) {
    SafeStorage.setItem("trmt_resume_" + email, JSON.stringify(data));
  },
  loadResume(email) {
    try {
      return JSON.parse(SafeStorage.getItem("trmt_resume_" + email)) || {};
    } catch {
      return {};
    }
  },
};

/* ════════════════════════════════════════════════
   STATE
════════════════════════════════════════════════ */
let currentUser = DB.session();
let userPhoto = null;
let userIdName = "";

/* ════════════════════════════════════════════════
   PAGE ROUTING
════════════════════════════════════════════════ */
function showPage(id) {
  document
    .querySelectorAll(".page")
    .forEach((p) => p.classList.remove("active"));
  document.getElementById("page-" + id).classList.add("active");
  window.scrollTo(0, 0);
  // Close mobile nav whenever we navigate
  const nav = document.getElementById("navRight");
  if (nav) nav.classList.remove("mobile-open");
  if (id === "builder" && currentUser) {
    loadSavedResume();
    updatePreview();
  }
  requestAnimationFrame(applyDynamicScale);
}

function handleCreateResume() {
  if (currentUser) showPage("builder");
  else openModal("signup");
}

/* ════════════════════════════════════════════════
   NAVBAR REFRESH
════════════════════════════════════════════════ */
function refreshNav() {
  const u = currentUser;
  const greet = document.getElementById("userGreet");
  greet.textContent = u ? "Hi, " + u.name.split(" ")[0] + "!" : "";
  greet.style.display = u ? "inline" : "none";
  document.getElementById("btnMyResume").style.display = u
    ? "inline-block"
    : "none";
  document.getElementById("btnLogout").style.display = u
    ? "inline-block"
    : "none";
  document.getElementById("btnLogin").style.display = u
    ? "none"
    : "inline-block";
  document.getElementById("btnSignup").style.display = u
    ? "none"
    : "inline-block";
}

/* ════════════════════════════════════════════════
   MODAL HELPERS
════════════════════════════════════════════════ */
function openModal(type) {
  document.getElementById(type + "Overlay").classList.add("open");
  document.body.style.overflow = "hidden";
}
function closeModal(id) {
  document.getElementById(id).classList.remove("open");
  document.body.style.overflow = "";
}
function closeOverlay(e, id) {
  if (e.target === e.currentTarget) closeModal(id);
}
function switchToSignup() {
  closeModal("loginOverlay");
  openModal("signup");
}
function switchToLogin() {
  closeModal("signupOverlay");
  openModal("login");
}

function showErr(el, msg) {
  el.textContent = "⚠ " + msg;
  el.style.display = "block";
}

/* ════════════════════════════════════════════════
   AUTH – LOGIN
════════════════════════════════════════════════ */
function doLogin() {
  const email = document.getElementById("li-email").value.trim();
  const pass = document.getElementById("li-pass").value;
  const err = document.getElementById("loginErr");
  err.style.display = "none";

  if (!email || !pass) {
    showErr(err, "Please fill all fields.");
    return;
  }

  const res = DB.login(email, pass);
  if (res.ok) {
    currentUser = res.user;
    refreshNav();
    closeModal("loginOverlay");
    showPage("builder");
  } else {
    showErr(err, res.msg);
  }
}

/* ════════════════════════════════════════════════
   AUTH – SIGNUP
════════════════════════════════════════════════ */
function doSignup() {
  const name = document.getElementById("su-name").value.trim();
  const email = document.getElementById("su-email").value.trim();
  const phone = document.getElementById("su-phone").value.trim();
  const pass = document.getElementById("su-pass").value;
  const conf = document.getElementById("su-conf").value;
  const err = document.getElementById("signupErr");
  const ok2 = document.getElementById("signupOk");
  err.style.display = "none";
  ok2.style.display = "none";

  if (!name || !email || !pass || !conf) {
    showErr(err, "Please fill all required fields.");
    return;
  }
  if (pass !== conf) {
    showErr(err, "Passwords do not match.");
    return;
  }
  if (pass.length < 6) {
    showErr(err, "Password must be at least 6 characters.");
    return;
  }

  const res = DB.register(name, email, phone, pass);
  if (res.ok) {
    ok2.textContent = "✅ Account created! Taking you to the builder...";
    ok2.style.display = "block";
    DB.login(email, pass);
    currentUser = DB.session();
    refreshNav();
    setTimeout(() => {
      closeModal("signupOverlay");
      showPage("builder");
    }, 1200);
  } else {
    showErr(err, res.msg);
  }
}

/* ════════════════════════════════════════════════
   AUTH – LOGOUT
════════════════════════════════════════════════ */
function doLogout() {
  DB.logout();
  currentUser = null;
  userPhoto = null;
  refreshNav();
  showPage("home");
}

/* ════════════════════════════════════════════════
   TABS (builder)
════════════════════════════════════════════════ */
function switchTab(id, btn) {
  document
    .querySelectorAll(".tab-panel")
    .forEach((p) => p.classList.remove("active"));
  document
    .querySelectorAll(".tab")
    .forEach((b) => b.classList.remove("active"));
  document.getElementById("tab-" + id).classList.add("active");
  btn.classList.add("active");
}

/* ════════════════════════════════════════════════
   FILE UPLOADS
════════════════════════════════════════════════ */
function handlePhotoUpload(input) {
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (e) => {
    userPhoto = e.target.result;
    document.getElementById("photoThumb").src = userPhoto;
    updatePreview();
  };
  reader.readAsDataURL(file);
}

function handleIDUpload(input) {
  const file = input.files[0];
  if (!file) return;
  userIdName = file.name;
  document.getElementById("idFileName").textContent = "✅ " + file.name;
  updatePreview();
}

/* ════════════════════════════════════════════════
   SAVE / LOAD RESUME
════════════════════════════════════════════════ */
function saveResume() {
  if (!currentUser) return;
  const data = getFormData();
  if (userPhoto) data.photo = userPhoto;
  if (userIdName) data.idName = userIdName;
  DB.saveResume(currentUser.email, data);
  const msg = document.getElementById("saveMsg");
  msg.style.display = "block";
  setTimeout(() => (msg.style.display = "none"), 2500);
}

function loadSavedResume() {
  if (!currentUser) return;
  const d = DB.loadResume(currentUser.email);
  if (!Object.keys(d).length) return;
  const map = {
    "f-name": d.name,
    "f-title": d.title,
    "f-addr": d.addr,
    "f-email": d.email,
    "f-phone": d.phone,
    "f-about": d.about,
    "f-edu": d.edu,
    "f-skills": d.skills,
    "f-cando": d.cando,
    "f-projects": d.projects,
  };
  for (const [id, val] of Object.entries(map)) {
    if (val) document.getElementById(id).value = val;
  }
  if (d.photo) {
    userPhoto = d.photo;
    document.getElementById("photoThumb").src = d.photo;
  }
  if (d.idName) {
    userIdName = d.idName;
    document.getElementById("idFileName").textContent = "✅ " + d.idName;
  }
}

function getFormData() {
  return {
    name: document.getElementById("f-name").value || "",
    title: document.getElementById("f-title").value || "",
    addr: document.getElementById("f-addr").value || "",
    email: document.getElementById("f-email").value || "",
    phone: document.getElementById("f-phone").value || "",
    about: document.getElementById("f-about").value || "",
    edu: document.getElementById("f-edu").value || "",
    skills: document.getElementById("f-skills").value || "",
    cando: document.getElementById("f-cando").value || "",
    projects: document.getElementById("f-projects").value || "",
  };
}

/* ════════════════════════════════════════════════
   RESUME CARD BUILDER  (pure HTML string)
════════════════════════════════════════════════ */
function esc(s) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function buildResumeHTML(
  name,
  addr,
  title,
  email,
  phone,
  about,
  eduLines,
  skillList,
  candoLines,
  projLines,
  idName,
  photo,
) {
  /* Skills bars */
  const skillBars = skillList
    .map((sk, i) => {
      const w = 70 + (i % 3) * 10;
      return `<div class="skill-wrap">
              <div class="skill-row"><span>${esc(sk)}</span><span>●●●●○</span></div>
              <div class="skill-bg"><div class="skill-fill" style="width:${w}%"></div></div>
            </div>`;
    })
    .join("");

  const eduHTML = eduLines
    .map(
      (e) => `<div class="edu-item"><div class="edu-deg">${esc(e)}</div></div>`,
    )
    .join("");
  const projHTML = projLines
    .map((p) => `<div class="proj-item">🔷 ${esc(p)}</div>`)
    .join("");
  const candoHTML = candoLines.map((c) => `<div>🔹 ${esc(c)}</div>`).join("");

  return `
  <div class="resume-card">
    <div class="r-sidebar">
      <div style="text-align:center">
        <img class="r-photo" src="${photo}" alt="Profile Photo">
        <div class="r-sname">${esc(name) || "YOUR NAME"}</div>
        <div class="r-stitle">${esc(title) || "Professional"}</div>
      </div>

      <div>
        <div class="s-heading">Contact</div>
        <div class="s-item">📍 ${esc(addr) || "City, Country"}</div>
        <div class="s-item">📧 ${esc(email) || "email@example.com"}</div>
        <div class="s-item">📞 ${esc(phone) || "+91 XXXXX XXXXX"}</div>
      </div>

      ${skillBars ? `<div><div class="s-heading">Skills</div>${skillBars}</div>` : ""}

      <div>
        <div class="s-heading">ID Document</div>
        <div class="id-box">
          <div style="font-size:22px;margin-bottom:4px">🪪</div>
          ${esc(idName) || "Not Uploaded Yet"}
        </div>
      </div>
    </div>

    <div class="r-main">
      <div class="r-mhead">
        <div class="r-mname">${esc(name) || "YOUR FULL NAME"}</div>
        <div class="r-maddr">📍 ${esc(addr) || "City, Country"}</div>
      </div>

      ${about ? `<div><div class="m-heading">About Me</div><p class="m-text">${esc(about)}</p></div>` : ""}
      ${eduHTML ? `<div><div class="m-heading">Education &amp; Degrees</div>${eduHTML}</div>` : ""}
      ${candoHTML ? `<div><div class="m-heading">What I Know &amp; Can Do</div><div class="m-text">${candoHTML}</div></div>` : ""}
      ${projHTML ? `<div><div class="m-heading">My Projects</div>${projHTML}</div>` : ""}
    </div>
  </div>`;
}

/* ════════════════════════════════════════════════
   LIVE PREVIEW  (builder page)
════════════════════════════════════════════════ */
function updatePreview() {
  const d = getFormData();
  const photo = userPhoto || OWNER_PHOTO;
  const skills = d.skills
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean);
  const edus = d.edu.split("\n").filter(Boolean);
  const projs = d.projects.split("\n").filter(Boolean);
  const cando = d.cando.split("\n").filter(Boolean);

  document.getElementById("previewInner").innerHTML = buildResumeHTML(
    d.name,
    d.addr,
    d.title,
    d.email,
    d.phone,
    d.about,
    edus,
    skills,
    cando,
    projs,
    userIdName,
    photo,
  );

  // Re-apply dynamic scale so preview fits its container on any screen
  requestAnimationFrame(applyDynamicScale);
}

