/* ════════════════════════════════════════════════
   DOWNLOAD RESUME AS PDF
════════════════════════════════════════════════ */
async function downloadResumePDF() {
  const pdfMsg = document.getElementById("pdfMsg");
  pdfMsg.style.display = "block";
  pdfMsg.textContent = "⏳ Generating PDF…";

  try {
    // Build a full-size hidden resume card for PDF capture
    const d = getFormData();
    const photo = userPhoto || OWNER_PHOTO;
    const skills = d.skills
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean);
    const edus = d.edu.split("\n").filter(Boolean);
    const projs = d.projects.split("\n").filter(Boolean);
    const cando = d.cando.split("\n").filter(Boolean);

    const html = buildResumeHTML(
      d.name,
      d.addr,
      d.title,
      d.email,
      d.phone,
      d.about,
      edus,
      skills,
      cando,
      projs,
      userIdName,
      photo,
    );

    // Create an off-screen container at full A4 width (794px)
    const container = document.createElement("div");
    container.style.cssText = `
      position: fixed; left: -9999px; top: 0;
      width: 794px; background: #fff;
      font-family: 'Nunito', sans-serif;
    `;
    container.innerHTML = html;
    document.body.appendChild(container);

    // Wait a tick for images to render
    await new Promise((r) => setTimeout(r, 400));

    const canvas = await html2canvas(container, {
      scale: 2,
      useCORS: true,
      allowTaint: true,
      backgroundColor: "#ffffff",
      logging: false,
    });

    document.body.removeChild(container);

    const { jsPDF } = window.jspdf;
    const pdf = new jsPDF({
      orientation: "portrait",
      unit: "mm",
      format: "a4",
    });

    const pageW = pdf.internal.pageSize.getWidth(); // 210 mm
    const pageH = pdf.internal.pageSize.getHeight(); // 297 mm

    const imgW = canvas.width;
    const imgH = canvas.height;
    const ratio = pageW / (imgW / 2); // canvas is @2x scale
    const pdfH = (imgH / 2) * ratio;

    const imgData = canvas.toDataURL("image/jpeg", 0.95);

    // If content spans more than one page, split it
    let yOffset = 0;
    while (yOffset < pdfH) {
      if (yOffset > 0) pdf.addPage();
      pdf.addImage(imgData, "JPEG", 0, -yOffset, pageW, pdfH);
      yOffset += pageH;
    }

    const name = d.name ? d.name.replace(/\s+/g, "_") : "Resume";
    pdf.save(name + "_Resume.pdf");

    pdfMsg.textContent = "✅ PDF downloaded!";
    setTimeout(() => {
      pdfMsg.style.display = "none";
    }, 3000);
  } catch (err) {
    console.error(err);
    pdfMsg.textContent = "❌ PDF generation failed. Please try again.";
    pdfMsg.style.color = "#e53e3e";
    setTimeout(() => {
      pdfMsg.style.display = "none";
      pdfMsg.style.color = "";
    }, 4000);
  }
}

/* ════════════════════════════════════════════════
   DYNAMIC RESUME SCALE — fills container on any screen
════════════════════════════════════════════════ */
function applyDynamicScale() {
  // All .scale-wrap elements inside .resume-wrap or .preview-box
  document
    .querySelectorAll(".resume-wrap .scale-wrap, .preview-box .scale-wrap")
    .forEach((sw) => {
      const parent = sw.parentElement;
      if (!parent) return;
      const containerW = parent.clientWidth;
      if (!containerW) return;
      const scale = containerW / 794; // resume card is always 794px wide
      sw.style.transform = `scale(${scale})`;
      sw.style.transformOrigin = "top left";
      // Adjust parent height to match scaled resume height (794×1123 ratio ≈ 1.414)
      parent.style.height = Math.round(1123 * scale) + "px";
    });
}

window.addEventListener("resize", applyDynamicScale);

/* ════════════════════════════════════════════════
   MOBILE NAV TOGGLE
════════════════════════════════════════════════ */
function toggleMobileNav() {
  const nav = document.getElementById("navRight");
  nav.classList.toggle("mobile-open");
}

window.addEventListener("DOMContentLoaded", () => {
  refreshNav();
  renderStaticCards();
  requestAnimationFrame(applyDynamicScale);

  /* Set default photo thumb */
  document.getElementById("photoThumb").src = OWNER_PHOTO;

  /* Pre-fill email in builder if user is logged in */
  if (currentUser) {
    const emailField = document.getElementById("f-email");
    if (emailField && !emailField.value)
      emailField.value = currentUser.email || "";
  }

  /* Initial preview render */
  updatePreview();

  /* Apply dynamic scaling for all devices */
  requestAnimationFrame(applyDynamicScale);
});
